import{_ as o,o as e,c as r,a2 as s}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"40 · Chrome：让它操作浏览器","description":"","frontmatter":{"head":[["meta",{"property":"og:site_name","content":"David Studio AI 编程指南"}]]},"headers":[],"relativePath":"claude-code/40-chrome.md","filePath":"claude-code/40-chrome.md"}'),a={name:"claude-code/40-chrome.md"};function n(d,t,p,l,c,h){return e(),r("div",null,[...t[0]||(t[0]=[s(`<h1 id="_40-·-chrome-让它操作浏览器" tabindex="-1">40 · Chrome：让它操作浏览器 <a class="header-anchor" href="#_40-·-chrome-让它操作浏览器" aria-label="Permalink to &quot;40 · Chrome：让它操作浏览器&quot;">​</a></h1><blockquote><p>📚 <strong>系列导航</strong>：上一篇 <a href="./39-getting-started-practice">39 实战入门</a> 把前面学的零件第一次拼成一条完整流程跑了一遍。这一篇给 Claude Code 再开一扇门——<strong>让它直接操作你的 Chrome 浏览器</strong>：开网页、读控制台报错、填表单、从页面里扒数据，全程不用你离开终端去手点。</p></blockquote><blockquote><p>⚠️ <strong>实验性功能，可能随版本变化。</strong> 本篇讲的 Chrome 集成目前处于测试版（beta），命令、前置版本、支持的浏览器都以官方文档为准，后续版本可能调整。</p></blockquote><p>兄弟们，今天聊一个能让 Claude Code「长出手」的功能——<strong>操作浏览器</strong>。</p><p>前面三十九篇里，Claude 干的活基本都在「文件 + 命令行」这一亩三分地：读你的代码、改你的文件、跑你的脚本。但<strong>真实开发里有一大堆事是离不开浏览器的</strong>——改完登录表单得打开页面点一下试试、报了个 bug 得看浏览器控制台（console）里红色的报错、设计稿还原得对着浏览器一像素一像素比。这些事，以前你只能自己切到 Chrome 手动来，然后把看到的复制回来喂给 Claude。</p><p><strong>现在不用了。</strong> 接上 Chrome 集成，你在终端里说一句「打开 localhost:3000，用错误数据提交那个表单，看看报错提示对不对」，Claude 自己就把浏览器开了、表单填了、报错读了，回头告诉你结果。<strong>「改代码」和「在浏览器里验代码」第一次能在同一个对话里从头到尾搞定</strong>，不用来回切窗口。</p><p>我第一次接上它那天，盯着自己那个 Chrome 自动弹出新标签页、鼠标点搜索框、一个字一个字敲进去，愣是看了一会儿——那种「它真的在替我点」的感觉，跟之前在沙箱里跑命令完全是两码事。</p><p>这么说吧：前面 MCP（详见第 22 篇）是给它接上了数据库、Jira 这些<strong>数据源</strong>；Chrome 集成是给它接上了<strong>你天天在用的那个浏览器本身</strong>——连着你所有的登录态。这一篇就讲清楚它能干嘛、怎么接、有哪些坑、以及操作你「真浏览器」这件事的安全边界在哪。</p><p><strong>看完这一篇，你会拿到：</strong></p><ul><li>一句话讲明白 Chrome 集成是什么、它和 MCP / computer use 各管哪一块</li><li>接上它的完整步骤（装扩展、<code>--chrome</code> 启动、前置版本和套餐要求），以及哪些浏览器 / 环境不支持</li><li>六类高频用例（实时调试、设计验证、填表单、扒数据……，选自官方列出的典型工作流），每类配一句你真实会怎么用</li><li>操作「真浏览器」相对沙箱的风险在哪、官方给了哪些护栏、你自己该守哪几条</li><li>一个能照着跑、给了预期结果的最小实战：接上 Chrome 让它读一次页面</li></ul><hr><h2 id="_01-先搞懂-它到底是什么、能干什么" tabindex="-1">01 先搞懂：它到底是什么、能干什么 <a class="header-anchor" href="#_01-先搞懂-它到底是什么、能干什么" aria-label="Permalink to &quot;01 先搞懂：它到底是什么、能干什么&quot;">​</a></h2><p>先给结论：<strong>Chrome 集成 = 让 Claude Code 借用你已经登录好一切的那个 Chrome，替你开网页、点按钮、填表单、读页面</strong>。</p><p>关键词是「<strong>你已经登录好的那个</strong>」。官方说得很直接：</p><blockquote><p>Claude 为浏览器任务打开新标签页，并共享您浏览器的登录状态，因此它可以访问您已登录的任何网站。浏览器操作在实时可见的 Chrome 窗口中运行。</p></blockquote><p>把这句话拆开，有三个点对小白特别重要：</p><ul><li><strong>开的是新标签页</strong>，不是另起一个陌生浏览器——它就在你眼前那个 Chrome 里干活。</li><li><strong>共享你的登录态</strong>——你 Gmail、Notion、公司后台都登录着，它直接就能进，不用你再配什么 API、贴什么 token。</li><li><strong>窗口实时可见</strong>——它点哪、填哪你全看得见，<strong>不是在后台偷偷摸摸</strong>。</li></ul><p><strong>类比：叫了个代驾。</strong> 你今晚喝了点酒，叫个代驾把你送回家。代驾开的不是他自己的车，<strong>是你这台车</strong>——车里插着你的 ETC、储物格放着你的停车卡、导航里存着你家地址，这些他全能直接用，你不用重新给他办一张卡。但方向盘你随时能要回来：遇到要刷脸的小区门禁（代驾刷不了），他停下让你来。Claude 操作浏览器就是这么个「代驾」——<strong>开的是你那台登录好一切的浏览器，该它干的它干，遇到登录页、验证码（CAPTCHA）这种它过不了的，它停下来喊你</strong>。</p><p>那它具体能干哪些活？官方列了一串，我挑出小白最有体感的几类，配上「你真实会怎么用」：</p><ul><li><strong>实时调试</strong>：直接读浏览器控制台的报错和页面 DOM 状态，然后<strong>回头就把导致报错的代码改了</strong>——这是它和 MCP 最不一样的地方，能「看见」浏览器里发生了啥。</li><li><strong>设计验证</strong>：照 Figma 稿写完 UI，<strong>打开浏览器比一比对不对得上</strong>（衔接第 17 篇讲的还原设计稿）。</li><li><strong>网页应用测试</strong>：测表单校验、查视觉有没有变形、验用户流程走不走得通。</li><li><strong>操作已登录的应用</strong>：直接在 Gmail、Notion、Google Docs 里写东西、改东西，<strong>不用 API 连接器</strong>。</li><li><strong>扒数据</strong>：把页面上的列表（名称、价格、库存）抽成结构化数据，存成本地 CSV。</li><li><strong>录 GIF</strong>：把一段浏览器操作录成 GIF，用来记录或者分享「这事儿是怎么发生的」。</li></ul><p>举个我自己印象最深的场景：有回调一个前端的诡异 bug，页面加载时控制台报一个 <code>undefined</code>，我对着代码看了快半小时也没看出哪错了。接上 Chrome 后我就甩了句「打开 dashboard 页，把加载时控制台里的报错念给我听，再定位是哪段代码」——它读完报错、顺着调用栈找到了一个没做空值判断的地方，<strong>前后不到两分钟</strong>。换以前我得自己开 F12、复制报错、再贴回终端描述一遍，光来回倒腾就比这久。</p><blockquote><p>💡 一句话总结：Chrome 集成让 Claude <strong>借用你那台登录好一切的浏览器</strong>开网页、读控制台、填表单、扒数据——<strong>「改代码」和「在浏览器里验」第一次能在同一个对话里完整跑通</strong>。</p></blockquote><hr><h2 id="_02-它和-mcp、computer-use-各管哪一块" tabindex="-1">02 它和 MCP、computer use 各管哪一块 <a class="header-anchor" href="#_02-它和-mcp、computer-use-各管哪一块" aria-label="Permalink to &quot;02 它和 MCP、computer use 各管哪一块&quot;">​</a></h2><p>接之前先把一个容易混的事捋清：<strong>Claude 操作「外部世界」有好几条路，Chrome 集成只是其中一条</strong>。三条路别搞混了，不然你会纠结「这事该用哪个」。</p><p>官方在 computer use 那页讲了一个<strong>优先级顺序</strong>——Claude 干外部的活，<strong>会从最精准的工具往最笨重的工具试</strong>：</p><blockquote><p>如果您有该服务的 MCP server，Claude 会使用它。如果任务是 shell 命令，Claude 会使用 Bash。如果任务是浏览器工作且您已设置 Claude in Chrome，Claude 会使用它。如果以上都不适用，Claude 会使用 computer use。</p></blockquote><p><strong>类比：能打电话办的事就别专门跑一趟。</strong> 同一件事，能发个消息说清的就发消息（最快），发消息说不清就打个电话（慢一点），电话也办不了才亲自上门跑一趟（最慢最费事）。Claude 也是这个排序——<strong>先试最省事的，最省事的够不着才升级到更重的手段</strong>。</p><p>三条路对照着看，你就知道各自的主场：</p><table tabindex="0"><thead><tr><th>手段</th><th>干什么</th><th>什么时候轮到它</th><th>本篇是它吗</th></tr></thead><tbody><tr><td><strong>MCP</strong>（详见第 22 篇）</td><td>连数据库、Jira、Slack 这些<strong>有接口的服务</strong></td><td>服务有现成 MCP server，最精准，优先用</td><td>否</td></tr><tr><td><strong>Chrome 集成</strong></td><td>操作<strong>浏览器里的网页</strong>：点、填、读控制台、扒数据</td><td>活儿是网页操作、又装了 Chrome 集成</td><td><strong>是</strong></td></tr><tr><td><strong>computer use</strong></td><td>控制<strong>本机原生 app</strong>：点 macOS 应用、看屏幕、截图</td><td>上面都够不着（原生应用、模拟器、没 API 的工具）</td><td>否，见下方</td></tr></tbody></table><p><strong>computer use（让 Claude 用你的电脑）</strong> 是兄弟篇，这里顺带提一句让你有个数。它比 Chrome 集成更「广」也更「慢」——<strong>Chrome 集成只能碰浏览器，computer use 能控制整个 macOS 桌面</strong>：打开原生 app、点任意按钮、截你的屏。官方原话：</p><blockquote><p>屏幕控制保留用于其他工具无法到达的事物：原生应用、模拟器和没有 API 的工具。</p></blockquote><p>几个关键差别记住就行（都以官方文档为准）：</p><ul><li><strong>computer use 目前是研究预览版，只在 macOS 上的 CLI 可用</strong>（Windows 用桌面 app 那条线，见第 10 篇），要 Pro / Max 套餐，且<strong>不支持 <code>-p</code> 非交互模式</strong>。</li><li>它在 <code>/mcp</code> 菜单里以一个叫 <code>computer-use</code> 的内置 server 出现，<strong>默认关着</strong>，要手动启用。</li><li>它跑在<strong>你真实的桌面上</strong>，会请求 macOS 的「辅助功能」和「屏幕录制」权限。</li></ul><p>一句话分工：<strong>有接口走 MCP，网页里的事走 Chrome，连原生桌面都得碰才上 computer use</strong>。这一篇专讲中间那条——Chrome。</p><blockquote><p>💡 一句话总结：Claude 碰外部世界<strong>从精准到笨重三条路</strong>——MCP（有接口的服务）→ Chrome（浏览器网页）→ computer use（整个 macOS 桌面）；本篇专讲 Chrome 这条，它的主场是<strong>浏览器里的操作</strong>。</p></blockquote><hr><h2 id="_03-怎么接上-装扩展、-chrome-启动" tabindex="-1">03 怎么接上：装扩展、<code>--chrome</code> 启动 <a class="header-anchor" href="#_03-怎么接上-装扩展、-chrome-启动" aria-label="Permalink to &quot;03 怎么接上：装扩展、\`--chrome\` 启动&quot;">​</a></h2><p>接 Chrome 集成，比接一个普通 MCP server 还简单——<strong>核心就两步：装个 Chrome 扩展，启动时带个 <code>--chrome</code> 标志</strong>。但有几个前置条件不满足就是接不上，先把门槛摆清楚。</p><h3 id="先对四个前置条件" tabindex="-1">先对四个前置条件 <a class="header-anchor" href="#先对四个前置条件" aria-label="Permalink to &quot;先对四个前置条件&quot;">​</a></h3><p>官方列了四条<strong>硬要求</strong>，差一条都连不上，挨个对一遍：</p><table tabindex="0"><thead><tr><th>前置条件</th><th>具体要求</th><th>怎么查</th></tr></thead><tbody><tr><td><strong>浏览器</strong></td><td>Google Chrome 或 Microsoft Edge</td><td>别的浏览器不行，见下方「不支持清单」</td></tr><tr><td><strong>Chrome 扩展</strong></td><td>「Claude in Chrome」扩展 <strong>v1.0.36 或更高</strong></td><td><code>chrome://extensions</code> 里看</td></tr><tr><td><strong>Claude Code 版本</strong></td><td><strong>v2.0.73 或更高</strong></td><td>终端跑 <code>claude --version</code></td></tr><tr><td><strong>套餐</strong></td><td>直接的 Anthropic 计划（Pro / Max / Team / Enterprise）</td><td><code>/status</code> 看订阅</td></tr></tbody></table><p>最后一条<strong>套餐</strong>最容易栽，单独强调一下。官方明确：</p><blockquote><p>Chrome 集成不可通过 Amazon Bedrock、Google Cloud Vertex AI 或 Microsoft Foundry 等第三方提供商获得。如果您仅通过第三方提供商访问 Claude，则需要单独的 claude.ai 账户来使用此功能。</p></blockquote><p>翻成人话：<strong>你要是走 Bedrock / Vertex / Foundry 这些第三方接入（第 05 篇讲过），或者只用 API key，这功能用不了</strong>——它只认直接的 Anthropic 订阅。这点和桌面 app、computer use 一个脾气，记住就行。</p><h3 id="哪些浏览器-环境不支持" tabindex="-1">哪些浏览器 / 环境不支持 <a class="header-anchor" href="#哪些浏览器-环境不支持" aria-label="Permalink to &quot;哪些浏览器 / 环境不支持&quot;">​</a></h3><p>这张「不支持清单」我专门拎出来，<strong>因为踩了会很懵</strong>：</p><ul><li><strong>浏览器</strong>：目前只支持 <strong>Chrome 和 Edge</strong>。Brave、Arc、以及其他基于 Chromium 的浏览器<strong>都不支持</strong>——别看它们也是 Chromium 内核就想当然。</li><li><strong>环境</strong>：<strong>不支持 WSL</strong>（Windows 子系统 Linux）。你在 WSL 里跑 Claude Code 想接 Windows 上的 Chrome，这条路目前不通。</li></ul><p>Arc 这个坑我亲自踩过。我日常主力浏览器就是 Arc（同样 Chromium 内核），想当然以为装上扩展就能用，结果 <code>/chrome</code> 死活连不上，扩展也装了、版本也对，就是不通。折腾了二十来分钟才翻到文档里那行小字「尚不支持 Brave、Arc 或其他基于 Chromium 的浏览器」——<strong>白忙活</strong>。后来老老实实单独装了个 Chrome 专门给它用，才秒连上。</p><h3 id="装扩展-启动" tabindex="-1">装扩展 + 启动 <a class="header-anchor" href="#装扩展-启动" aria-label="Permalink to &quot;装扩展 + 启动&quot;">​</a></h3><p>前置条件齐了，正式接：</p><p><strong>第一步：装「Claude in Chrome」扩展。</strong> 去 Chrome 应用商店搜「Claude」装上（Edge 也是在 Chrome 应用商店装同一个）。</p><blockquote><p>装扩展、访问 Chrome 应用商店在国内一般需要「魔法上网」；扩展本身要连 Anthropic，网络不通时也连不上。</p></blockquote><p><strong>第二步：带 <code>--chrome</code> 启动 Claude Code。</strong> 在终端：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --chrome</span></span></code></pre></div><p>或者你已经在一个会话里了，直接敲 <code>/chrome</code> 启用，不用退出重开。</p><p><strong>就这两步。</strong> 接上之后，任何时候敲 <code>/chrome</code> 都能：<strong>检查连接状态、管理权限、重新连接扩展、选用哪个已连接的浏览器</strong>。要是同时连了多个浏览器，浏览器操作一开始 Claude 会问你用哪个。</p><h3 id="不想每次都打-chrome" tabindex="-1">不想每次都打 <code>--chrome</code>？ <a class="header-anchor" href="#不想每次都打-chrome" aria-label="Permalink to &quot;不想每次都打 \`--chrome\`？&quot;">​</a></h3><p>嫌每个会话都加 <code>--chrome</code> 烦，可以设成默认：<strong>运行 <code>/chrome</code>，选「默认启用」</strong>。</p><p>但官方专门提醒了一句<strong>代价</strong>，值得你想清楚再开：</p><blockquote><p>在 CLI 中默认启用 Chrome 会增加上下文使用，因为浏览器工具始终被加载。如果您注意到上下文消耗增加，请禁用此设置，仅在需要时使用 <code>--chrome</code>。</p></blockquote><p>说白了：<strong>默认启用 = 浏览器那套工具每次会话都常驻</strong>，会吃掉一截上下文窗口（第 19 篇讲过工作台塞满会变蠢）。一般来说更稳的做法是<strong>不设默认，需要操作浏览器的会话才临时 <code>--chrome</code></strong>——大多数纯改代码的活根本用不上浏览器，没必要让它一直占着地方。</p><blockquote><p>顺带一提：如果你主力在 <strong>VS Code 扩展</strong>（第 08 篇）里干活，只要装了 Chrome 扩展，<strong>浏览器自动化就直接可用，不用加任何标志</strong>——这点比 CLI 省心。</p></blockquote><h3 id="网站权限从哪管" tabindex="-1">网站权限从哪管 <a class="header-anchor" href="#网站权限从哪管" aria-label="Permalink to &quot;网站权限从哪管&quot;">​</a></h3><p>还有个细节：<strong>Claude 能浏览、点击、输入哪些网站，是从 Chrome 扩展那边继承的</strong>。官方：</p><blockquote><p>网站级权限从 Chrome 扩展程序继承。在 Chrome 扩展程序设置中管理权限，以控制 Claude 可以浏览、点击和输入的网站。</p></blockquote><p>也就是说，<strong>控制它能碰哪些站，去 Chrome 扩展的设置里调</strong>，不在 Claude Code 这边。这是它的第一道闸，下一节讲安全会再提。</p><blockquote><p>💡 一句话总结：接 Chrome 就两步——<strong>装「Claude in Chrome」扩展 + 用 <code>--chrome</code> 启动</strong>（或会话里 <code>/chrome</code>）；但先对齐四个前置（浏览器、扩展版本、CC 版本、Anthropic 订阅），且 <strong>Brave / Arc / 其他 Chromium、WSL 都不支持</strong>。</p></blockquote><hr><h2 id="_04-典型用例-六类活儿-照着抄" tabindex="-1">04 典型用例：六类活儿，照着抄 <a class="header-anchor" href="#_04-典型用例-六类活儿-照着抄" aria-label="Permalink to &quot;04 典型用例：六类活儿，照着抄&quot;">​</a></h2><p>接上只是开始，会用才值钱。官方给了一串示例工作流，我按「你大概率会遇到」的顺序，把六类最实用的拎出来，<strong>每类给一条可以直接照着改的指令</strong>。这些指令都是用自然语言说的，你照着套自己的场景就行。</p><h3 id="用例一-测本地网页应用" tabindex="-1">用例一：测本地网页应用 <a class="header-anchor" href="#用例一-测本地网页应用" aria-label="Permalink to &quot;用例一：测本地网页应用&quot;">​</a></h3><p>开发时改完一个功能，让它直接帮你在浏览器里验：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我刚改了登录表单的校验逻辑。打开 localhost:3000，</span></span>
<span class="line"><span>用一组无效数据提交表单，看看错误提示有没有正确出现。</span></span></code></pre></div><p>它会导航到你的本地服务器、跟表单交互、把观察到的结果报给你。<strong>这大概是用得最多的一类</strong>——改完前端不用自己切浏览器手点，它替你跑一遍验证流程。</p><h3 id="用例二-用控制台日志调试" tabindex="-1">用例二：用控制台日志调试 <a class="header-anchor" href="#用例二-用控制台日志调试" aria-label="Permalink to &quot;用例二：用控制台日志调试&quot;">​</a></h3><p>让它读浏览器控制台帮你定位问题。<strong>这里有个官方给的诀窍</strong>：别让它「把所有控制台输出都给我」，日志太长会刷屏——<strong>告诉它你要找的模式</strong>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>打开 dashboard 页面，检查页面加载时控制台里有没有报错。</span></span></code></pre></div><p>它会读控制台消息，<strong>按你说的模式或错误类型过滤</strong>，不会把一大堆无关日志全倒给你。</p><h3 id="用例三-批量填表单" tabindex="-1">用例三：批量填表单 <a class="header-anchor" href="#用例三-批量填表单" aria-label="Permalink to &quot;用例三：批量填表单&quot;">​</a></h3><p>重复的数据录入最适合丢给它：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我有一个客户联系人表格在 contacts.csv 里。对每一行，</span></span>
<span class="line"><span>打开 crm.example.com 的 CRM，点「添加联系人」，</span></span>
<span class="line"><span>把姓名、邮箱、电话填进去。</span></span></code></pre></div><p>它读你的本地文件、操作网页界面、一条条录进去。<strong>说句实话，这类「机械重复」的活儿是它最香的用武之地</strong>——你只要把数据准备好，剩下的它照着填。</p><h3 id="用例四-直接在已登录的应用里写东西" tabindex="-1">用例四：直接在已登录的应用里写东西 <a class="header-anchor" href="#用例四-直接在已登录的应用里写东西" aria-label="Permalink to &quot;用例四：直接在已登录的应用里写东西&quot;">​</a></h3><p>这类最能体现「共享登录态」的爽：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>根据最近的几个 commit 起草一份项目进展更新，</span></span>
<span class="line"><span>加到我那份 Google Doc（docs.google.com/document/d/abc123）里。</span></span></code></pre></div><p>它打开文档、点进编辑器、把内容敲进去。<strong>Gmail、Notion、Sheets——凡是你已经登录的网页应用都吃这套，不用配任何 API。</strong></p><h3 id="用例五-从网页扒结构化数据" tabindex="-1">用例五：从网页扒结构化数据 <a class="header-anchor" href="#用例五-从网页扒结构化数据" aria-label="Permalink to &quot;用例五：从网页扒结构化数据&quot;">​</a></h3><p>把页面上散着的信息抽成规整的数据：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>打开商品列表页，把每件商品的名称、价格、库存状态抽出来，</span></span>
<span class="line"><span>存成一个 CSV 文件。</span></span></code></pre></div><p>它导航到页面、读内容、编译成结构化格式存到本地。</p><h3 id="用例六-录一段操作-gif" tabindex="-1">用例六：录一段操作 GIF <a class="header-anchor" href="#用例六-录一段操作-gif" aria-label="Permalink to &quot;用例六：录一段操作 GIF&quot;">​</a></h3><p>想给同事演示「这功能怎么走」，让它录：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>录一个 GIF，展示怎么走完整个结账流程，</span></span>
<span class="line"><span>从把商品加进购物车一直到确认页。</span></span></code></pre></div><p>它把这段交互序列录下来、存成 GIF 文件。<strong>写文档、提 issue 配个动图，比打一堆字描述清楚多了。</strong></p><p>把这六类对照「以前怎么干」摆一下，你就知道它省在哪：</p><table tabindex="0"><thead><tr><th>场景</th><th>❌ 没有 Chrome 集成</th><th>✅ 有 Chrome 集成</th></tr></thead><tbody><tr><td>验证前端改动</td><td>自己切浏览器手点、看效果、回来描述</td><td>一句话让它打开页面跑一遍报结果</td></tr><tr><td>调控制台报错</td><td>F12 开控制台、复制报错、贴回终端</td><td>让它直接读控制台、过滤出报错</td></tr><tr><td>批量录数据</td><td>一条条手动复制粘贴进网页</td><td>喂个 CSV，它照着逐行填</td></tr><tr><td>在 Notion / Docs 写</td><td>自己整理好再粘进去</td><td>让它直接进文档写（共享登录态）</td></tr></tbody></table><p><strong>提醒：</strong> <code>/mcp</code> 选 <code>claude-in-chrome</code> 能看到这些浏览器工具的<strong>完整列表</strong>，想知道它到底有哪些「手上的动作」，去那儿翻。官方还列了「多站点工作流」这类用例，这里略过，有兴趣可自行在 <code>/mcp</code> → <code>claude-in-chrome</code> 里探索。</p><blockquote><p>💡 一句话总结：六类高频用例——<strong>测本地应用、读控制台调 bug、批量填表单、在已登录应用里写、扒页面数据、录演示 GIF</strong>，每类一句自然语言指令就能让它干，核心都是「<strong>省掉你手动切浏览器那一段</strong>」。</p></blockquote><hr><h2 id="_05-安全-操作「真浏览器」的风险在哪" tabindex="-1">05 安全：操作「真浏览器」的风险在哪 <a class="header-anchor" href="#_05-安全-操作「真浏览器」的风险在哪" aria-label="Permalink to &quot;05 安全：操作「真浏览器」的风险在哪&quot;">​</a></h2><p>这一节最不能跳过——<strong>因为它操作的是你真实的、登录着一切的浏览器，不是一个用完即焚的沙箱</strong>。这跟前面 Claude 在沙箱里跑命令（第 21 篇）是完全不同的信任边界。</p><h3 id="风险到底在哪" tabindex="-1">风险到底在哪 <a class="header-anchor" href="#风险到底在哪" aria-label="Permalink to &quot;风险到底在哪&quot;">​</a></h3><p>回到「代驾」那个比方：代驾开的是<strong>你那台插着 ETC、放着停车卡的车</strong>。方便是真方便，但风险也实打实——<strong>他在你车里、用着你所有的卡</strong>。Chrome 集成同理：它共享你的登录态，意味着<strong>它能进的，是你登录着的所有网站</strong>——你的邮箱、你的公司后台、你的银行页面（只要你登录着）。</p><p>具体两类风险你得有数：</p><ul><li><strong>登录态等于钥匙串</strong>：它访问网站不需要再认证，<strong>你登录了什么，它就够得着什么</strong>。让它去某个页面操作时，心里要清楚这台浏览器上还登录着哪些敏感账号。</li><li><strong>提示注入（prompt injection）</strong>：这个第 21 篇专门讲过——<strong>网页内容里可能藏着「写给 AI 看」的恶意指令</strong>。它读一个页面时，页面上某段文字可能在偷偷指挥它干别的。操作浏览器时这个风险格外真实，因为它读的全是<strong>外部的、你控制不了的网页内容</strong>。</li></ul><h3 id="官方给了哪些护栏" tabindex="-1">官方给了哪些护栏 <a class="header-anchor" href="#官方给了哪些护栏" aria-label="Permalink to &quot;官方给了哪些护栏&quot;">​</a></h3><p>好在 Chrome 集成不是「敞开了让它乱来」，内置了几道闸：</p><ul><li><strong>遇到登录 / 验证码会停下喊你</strong>：碰到登录页或 CAPTCHA，它<strong>暂停、要你手动处理</strong>，不会替你瞎填、瞎点过。</li><li><strong>操作实时可见</strong>：它在一个<strong>你看得见的 Chrome 窗口</strong>里干活，点哪填哪你全程盯得到，不对劲随时能掐。</li><li><strong>网站权限可控</strong>：上一节说的，<strong>在 Chrome 扩展设置里限定它能碰哪些网站</strong>——这是你最该用起来的一道闸，把它能动的范围圈小。</li></ul><h3 id="你自己该守的几条" tabindex="-1">你自己该守的几条 <a class="header-anchor" href="#你自己该守的几条" aria-label="Permalink to &quot;你自己该守的几条&quot;">​</a></h3><p>官方护栏之外，还有几条操作真浏览器的土规矩值得记下来：</p><table tabindex="0"><thead><tr><th>场景</th><th>该怎么办</th></tr></thead><tbody><tr><td>让它操作浏览器前</td><td>先想清楚这台 Chrome 上还<strong>登录着哪些敏感账号</strong></td></tr><tr><td>涉及钱 / 不可逆操作（下单、转账、删数据）</td><td>⚠️ 自己来，别交给它，或全程死盯每一步</td></tr><tr><td>给它操作的网站范围</td><td>✅ 在扩展设置里<strong>圈小</strong>，只放它确实需要的站</td></tr><tr><td>让它访问陌生 / 不可信网页</td><td>⚠️ 警惕提示注入，内容里的「指令」别让它照单全收</td></tr></tbody></table><p>总原则就一条：<strong>它在浏览器里点的每一下都是「真的」</strong>——不像沙箱里跑错了删个容器重来，浏览器里点了「确认付款」就是真付了。所以<strong>越是不可逆、越是涉及钱的操作，越要自己把着方向盘</strong>，让它干那些「错了也好收拾」的活。</p><blockquote><p>这跟前面所有篇章的安全主线是一根弦：<strong>便利和风险成正比</strong>。Chrome 集成把便利拉满了——直接用你登录态——那对应的，你得把「它能碰什么」这道闸也守紧。</p></blockquote><blockquote><p>💡 一句话总结：Chrome 集成操作的是<strong>你登录着一切的真浏览器</strong>，不是沙箱——风险在「登录态即钥匙」和「网页里的提示注入」；官方护栏有「遇登录 / 验证码停手、操作可见、网站权限可控」，你自己则要<strong>圈小网站范围、把不可逆和涉钱操作攥在自己手里</strong>。</p></blockquote><hr><h2 id="_06-动手-接上-chrome-让它读一次页面" tabindex="-1">06 动手：接上 Chrome，让它读一次页面 <a class="header-anchor" href="#_06-动手-接上-chrome-让它读一次页面" aria-label="Permalink to &quot;06 动手：接上 Chrome，让它读一次页面&quot;">​</a></h2><p>光看不练假把式。下面带你跑一个<strong>最小实战</strong>：接上 Chrome，让它打开一个网页、读点东西回来。全程不碰你的敏感账号，<strong>专门拿来验证「接通了没」</strong>。</p><blockquote><p>前提：你得是 Pro / Max / Team / Enterprise 直接订阅（不是 Bedrock / Vertex / API key），装好 Chrome 或 Edge。装扩展、访问网页可能需要「魔法上网」。</p></blockquote><p><strong>第一步：装「Claude in Chrome」扩展</strong></p><p>在 Chrome 应用商店搜「Claude」，装上官方扩展。装完去 <code>chrome://extensions</code> 确认它<strong>已启用、版本 ≥ 1.0.36</strong>。</p><p>✅ 自验：扩展列表里能看到「Claude」且是开启状态。</p><p><strong>第二步：确认 Claude Code 版本够新</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><p><strong>预期</strong>：打印的版本号 <strong>≥ 2.0.73</strong>。低了就先升级（<code>npm update -g @anthropic-ai/claude-code</code> 或按第 02 篇的方式更新），否则接不上。</p><p><strong>第三步：带 <code>--chrome</code> 启动</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --chrome</span></span></code></pre></div><p>进去后敲 <code>/chrome</code> 看状态：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/chrome</span></span></code></pre></div><p><strong>预期</strong>：显示 Chrome 已连接、扩展状态正常。<strong>如果提示没检测到扩展</strong>，按官方排查：确认扩展已装并启用 → 确认 CC 是最新 → 确认 Chrome 在运行 → <code>/chrome</code> 选「重新连接扩展程序」。<strong>第一次启用时它会装一个本机消息传递配置，Chrome 要重启一次才读得到</strong>——头一回连不上，先重启 Chrome 再试。</p><p><strong>第四步：让它打开页面读点东西</strong></p><p>连上后，给它一条「只读、不碰敏感账号」的指令（官方文档站正好拿来练手）：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>打开 code.claude.com/docs，点一下搜索框，</span></span>
<span class="line"><span>输入「hooks」，把出现的结果告诉我。</span></span></code></pre></div><p><strong>预期</strong>：你会<strong>看见你那个 Chrome 弹出新标签页</strong>、自动导航过去、点搜索框、敲字——<strong>全程肉眼可见</strong>（这就是第 05 节说的「操作实时可见」）。然后它把搜到的结果列回终端。<strong>看到浏览器真的动起来、结果回来了 = 接通成功。</strong></p><blockquote><p>如果操作到一半浏览器没反应了，官方提示先查<strong>有没有弹出的对话框（alert / confirm）挡着页面</strong>——JavaScript 对话框会卡住浏览器事件；手动关掉再让它继续。长时间不动后断连，就 <code>/chrome</code> 选「重新连接扩展程序」（扩展的后台 service worker 会进空闲状态）。</p></blockquote><p>跑通这四步，你就把「装扩展 → 启动 → 验连接 → 让它操作页面」这条完整链路走了一遍。<strong>以后让它干任何浏览器的活，本质都是这套，无非把第四步换成你真实的任务。</strong></p><blockquote><p>💡 一句话总结：动手就四步——<strong>装扩展、<code>claude --chrome</code> 启动、<code>/chrome</code> 验连接、给一条只读指令看浏览器真动起来</strong>；头回连不上多半是扩展没装好或 Chrome 没重启，按官方那串排查走一遍。</p></blockquote><hr><h2 id="_07-小结" tabindex="-1">07 小结 <a class="header-anchor" href="#_07-小结" aria-label="Permalink to &quot;07 小结&quot;">​</a></h2><p>这一篇给 Claude Code 接上了<strong>你天天在用的那个浏览器</strong>——从「只会摸文件和命令行」，到能开网页、读控制台、填表单、扒数据，<strong>「改代码」和「在浏览器里验」这两件事终于能在一个对话里从头到尾跑完</strong>。</p><p>把核心串起来回顾：</p><table tabindex="0"><thead><tr><th>你要做的事</th><th>关键点</th></tr></thead><tbody><tr><td>理解它是什么</td><td>借用你<strong>登录好一切的真 Chrome</strong>，开新标签页操作，实时可见</td></tr><tr><td>分清它和别的工具</td><td><strong>MCP（有接口）→ Chrome（网页）→ computer use（整个桌面）</strong> 三条路，从精准到笨重</td></tr><tr><td>接上它</td><td>装「Claude in Chrome」扩展 + <code>--chrome</code> 启动；对齐扩展 / CC 版本、要 Anthropic 直接订阅</td></tr><tr><td>知道哪不支持</td><td><strong>Brave / Arc / 其他 Chromium、WSL 都不行</strong>，只支持 Chrome / Edge</td></tr><tr><td>会用</td><td>测本地应用、读控制台、批量填表单、在已登录应用写、扒数据、录 GIF</td></tr><tr><td>守住安全</td><td>操作的是<strong>真浏览器</strong>（非沙箱）：圈小网站权限、不可逆和涉钱操作自己来、警惕提示注入</td></tr></tbody></table><p><strong>你现在应该能：</strong> 讲清 Chrome 集成是什么、它和 MCP / computer use 各管哪一块，独立把它接上（装扩展 + <code>--chrome</code>），用自然语言指令让它干六类常见的浏览器活儿，并且清楚操作真浏览器的风险在哪、该守哪几条闸。<strong>这一接，Claude Code 从「本地代码助手」又往前迈了一步——能直接替你操作那个你最常打交道的窗口了。</strong></p><hr><p>下一篇 <strong>41「并行任务」</strong>——这一篇让一个 Claude 能操作浏览器了，但活儿一多，你会发现<strong>一个会话串着干还是慢</strong>：它开浏览器测着 A 功能，你 B、C 两个需求只能干等着。下一篇换个思路：<strong>怎么让多个任务真正并行铺开、各干各的、互不打扰</strong>。想想看：如果改前端、跑测试、扒数据这三件事能同时进行，而不是排队等一个 Claude 来回切，是不是又能省下一大段时间？</p>`,145)])])}const u=o(a,[["render",n]]);export{g as __pageData,u as default};
